import template from './sw-cms-el-config-blog-assignment.html.twig';
import './sw-cms-el-config-blog-assignment.scss';

const { Mixin } = Shopware;
const { Criteria } = Shopware.Data;

/**
 * @private
 * @package buyers-experience
 */
export default {
    template,

    inject: ['repositoryFactory'],

    mixins: [Mixin.getByName('cms-element')],

    computed: {
        productRepository() {
            return this.repositoryFactory.create('product');
        },

        productSelectContext() {
            return {
                ...Shopware.Context.api,
                inheritance: true,
            };
        },

        productCriteria() {
            const criteria = new Criteria(1, 25);
            criteria.addAssociation('options.group');
            criteria.addAssociation('assignedBlogs');

            return criteria;
        },

        selectedProductCriteria() {
            const criteria = new Criteria(1, 25);
            criteria.addAssociation('assignedBlogs');

            return criteria;
        },

        isProductPageType() {
            return this.cmsPageState?.currentPage?.type === 'product_detail';
        },
    },

    created() {
        this.createdComponent();
    },

    methods: {
        createdComponent() {
            this.initElementConfig('blog-assignment');
        },

        onProductChange(productId) {
            if (!productId) {
                this.element.config.product.value = null;
                this.element.data.product = null;
            } else {
                this.productRepository
                    .get(
                        productId,
                        this.productSelectContext,
                        this.selectedProductCriteria,
                    )
                    .then((product) => {
                        this.element.config.product.value = productId;
                        this.element.data.product = product;
                    });
            }

            this.$emit('element-update', this.element);
        },
    },
};
